var b="url",c="面料采购清单.html",d="generationDate",e=new Date(1781592921987.22),f="defaultAdaptiveView",g="name",h="",i="size",j="width",k=0,l="height",m="adaptiveViews",n="sketchKeys",o="s0",p="variables",q="OnLoadVariable",r="page",s="packageId",t="916f8213a5e14d538ee17cf8550a1756",u="type",v="Axure:Page",w="面料采购清单",x="notes",y="annotations",z="fn",A="1",B="ownerId",C="1d2f80e272f7429bbca95bf595e79660",D="label",E="(文本框)",F="说明",G="<p><span>1.提示字：采购单号</span></p><p><span>2.通过【搜索】后生效</span></p><p><span>&nbsp;&nbsp; &nbsp; &nbsp; a.模糊匹配'采购单号'列</span></p>",H="2",I="061800d481c8406e8a8c9d0e6daecdf6",J="<p><span>1.提示字：物料规格</span></p><p><span>2.通过【搜索】后生效</span></p><p><span>&nbsp;&nbsp; &nbsp; &nbsp; a.模糊匹配'规格/门幅'列</span></p>",K="3",L="10afb575c8d94b8595c75740c6e968ff",M="  选择物料",N="<p><span style=\"font-family:'Nunito Sans Bold', 'Nunito Sans', sans-serif;font-weight:700;color:#02A7F0;\">下拉选项</span></p><p><span>1.未选中提示字：选择物料</span></p><p><span>2.数据源：[基础数据系统&gt;&gt;物料管理：物料明细]中 </span><span style=\"font-family:'Nunito Sans Bold', 'Nunito Sans', sans-serif;font-weight:700;\">属性==</span><span style=\"font-family:'Nunito Sans Bold', 'Nunito Sans', sans-serif;font-weight:700;color:#D9001B;\">面料</span><span style=\"font-family:'Nunito Sans Bold Oblique', 'Nunito Sans Bold', 'Nunito Sans', sans-serif;font-weight:700;font-style:oblique;\"> </span><span>的'物料'</span></p><p><span>&nbsp;&nbsp; &nbsp; &nbsp;&nbsp; a.下拉展示“物料编码”和“物料名称”2列</span></p><p><span>&nbsp;&nbsp; &nbsp; &nbsp;&nbsp; b.支持对展示字段列的模糊搜索</span></p><p><span>&nbsp;&nbsp; &nbsp; &nbsp;&nbsp; c.右侧含“×‘的快捷清空按钮</span></p><p><span>3.选中或清空后</span></p><p><span>&nbsp;&nbsp; &nbsp; &nbsp;&nbsp; a.将“物料名称”返回当前下拉域</span></p><p><span>&nbsp;&nbsp; &nbsp; &nbsp;&nbsp; b.直接返回筛选结果</span></p>",O="4",P="a7c2099eb72f4fae87d5868ca29c28c6",Q="  物料颜色",R="<p><span style=\"font-family:'Nunito Sans Bold', 'Nunito Sans', sans-serif;font-weight:700;color:#02A7F0;\">下拉选项</span></p><p><span>1.未选中提示字：物料颜色</span></p><p><span>2.数据源：[基础数据系统&gt;&gt;物料管理：物料颜色]中全部'颜色'</span></p><p><span>&nbsp;&nbsp; &nbsp; &nbsp;&nbsp; a.下拉展示“色号”、“颜色”、“颜色(中)”、“颜色(英)”、“供色单位”</span></p><p><span>&nbsp;&nbsp; &nbsp; &nbsp;&nbsp; b.支持对展示字段列的模糊搜索</span></p><p><span>&nbsp;&nbsp; &nbsp; &nbsp;&nbsp; c.右侧含“×‘的快捷清空按钮</span></p><p><span>3.选中或清空后</span></p><p><span>&nbsp;&nbsp; &nbsp; &nbsp;&nbsp; a.将“颜色”返回当前下拉域</span></p><p><span>&nbsp;&nbsp; &nbsp; &nbsp;&nbsp; b.直接返回筛选结果</span></p>",S="5",T="50d5b2c28a5849968d2a354c8f0548ff",U="(下拉列表)",V="<p><span>1.默认展示全部结果</span></p><p><span>&nbsp;&nbsp; &nbsp; &nbsp;&nbsp; a.提示字：请选择供应商</span></p><p><span>2.数据源：[基础数据系统&gt;&gt;供应商管理：供应商资料]中全部的供应商</span></p><p><span>&nbsp;&nbsp; &nbsp; &nbsp;&nbsp; a.下拉支持模糊查询“供应商名称”</span></p><p><span>3.下拉选中后，列表直接返回结果</span></p><p><span>4.右侧含“×”的快捷清除按钮</span></p>",W="6",X="b9086668a2cd46e482b60afb9416a394",Y="<p><span>1.默认展示全部结果</span></p><p><span>&nbsp;&nbsp; &nbsp; &nbsp;&nbsp; a.提示字：入库状态</span></p><p><span>2.可选项：①进行中 ②手动关闭</span></p><p><span>3.右侧含“×”的快捷清除按钮</span></p><p><span>4.选中/清除后，列表直接返回结果</span></p>",Z="7",ba="88c33d6e8fad4cc6bf6d6d1013efb984",bb="<p><span>1.开始日期提示字：预计到货开始</span></p><p><span>2.结束日期提示字：预计到货结束</span></p><p><span>3.以日期(年/月/日)为区间进行筛选</span></p><p><span>4.快捷选项</span></p><p><span>&nbsp;&nbsp; &nbsp; &nbsp;&nbsp; a.今日（例：2024/02/01-2024/02/01）</span></p><p><span>&nbsp;&nbsp; &nbsp; &nbsp;&nbsp; b.未来7天（例：2024/02/01-2024/02/07）</span></p><p><span>5.选中后立即返回筛选结果</span></p><p><span>&nbsp;&nbsp; &nbsp; &nbsp;&nbsp; a.'预计到货'为空的行，有筛选区间时不展示</span></p>",bc="8",bd="e1894dc6da184df4be4ecb62c4327cd9",be="适用生产",bf="<p><span style=\"font-family:'Nunito Sans Bold', 'Nunito Sans', sans-serif;font-weight:700;color:#02A7F0;\">下拉选项</span></p><p><span>1.未选中提示字：关联生产</span></p><p><span>2.数据源：生产订单(SCDD)</span></p><p><span>&nbsp;&nbsp; &nbsp; &nbsp;&nbsp; a.下拉展示“生产订单”、“工作号”和“款号”3列</span></p><p><span>&nbsp;&nbsp; &nbsp; &nbsp;&nbsp; b.支持对展示字段列的模糊搜索</span></p><p><span>3.选中或清空后</span></p><p><span>&nbsp;&nbsp; &nbsp; &nbsp;&nbsp; a.将“生产订单”返回当前下拉域</span></p><p><span>&nbsp;&nbsp; &nbsp; &nbsp;&nbsp; b.将'关联款'的已选项清空</span></p><p><span>&nbsp;&nbsp; &nbsp; &nbsp;&nbsp; c.直接返回筛选结果</span></p>",bg="9",bh="301ec43e10fa46dd96326d4407307091",bi="适用款",bj="<p><span style=\"font-family:'Nunito Sans Bold', 'Nunito Sans', sans-serif;font-weight:700;color:#02A7F0;\">下拉选项</span></p><p><span>1.未选中提示字：</span><span style=\"color:#333333;\">关联</span><span>款</span></p><p><span>2.数据源：[基础数据系统&gt;&gt;款式管理：款式列表]中的全部'款式'</span></p><p><span>&nbsp;&nbsp; &nbsp; &nbsp;&nbsp; a.展示款式对应的“款号”、“款名”</span></p><p><span>&nbsp;&nbsp; &nbsp; &nbsp;&nbsp; b.支持对展示字段列的模糊搜索</span></p><p><span>3.选中或清空后</span></p><p><span>&nbsp;&nbsp; &nbsp; &nbsp;&nbsp; a.将“款号”返回当前下拉域</span></p><p><span>&nbsp;&nbsp; &nbsp; &nbsp;&nbsp; b.将'关联生产'的已选项清空</span></p><p><span>&nbsp;&nbsp; &nbsp; &nbsp;&nbsp; c.直接返回筛选结果</span></p>",bk="10",bl="cd4acbde4442477cb866fa688115a4c3",bm="汇总",bn="<p><span>采购数量：</span><span style=\"font-family:'Nunito Sans Bold', 'Nunito Sans', sans-serif;font-weight:700;color:#D9001B;\">Σ“采购数量”</span></p><p><span>入库数量：</span><span style=\"font-family:'Nunito Sans Bold', 'Nunito Sans', sans-serif;font-weight:700;color:#D9001B;\">Σ“采购入库数量”</span></p><p><span>退货数量：</span><span style=\"font-family:'Nunito Sans Bold', 'Nunito Sans', sans-serif;font-weight:700;color:#D9001B;\">Σ“退货出库数量”</span></p><p><span>待入库数：仅汇总状态为</span><span style=\"color:#4B7902;\">'进行中'</span><span>且</span><span style=\"color:#4B7902;\">'待入库数＞0'</span><span>的数据行中的</span><span style=\"font-family:'Nunito Sans Bold', 'Nunito Sans', sans-serif;font-weight:700;color:#D9001B;\">Σ“待入库数”</span></p>",bo="11",bp="b8c6c8eb0a6d47dfbd8c4c2f82f78ae5",bq="关闭",br="<p><span style=\"font-family:'Nunito Sans Regular', 'Nunito Sans', sans-serif;font-weight:400;\">1.校验是否存在勾选行</span></p><p><span style=\"font-family:'Nunito Sans Regular', 'Nunito Sans', sans-serif;font-weight:400;\">&nbsp;&nbsp; &nbsp; &nbsp;&nbsp; a.勾选为空：Toast提示“请勾选采购行”</span></p><p><span style=\"font-family:'Nunito Sans Regular', 'Nunito Sans', sans-serif;font-weight:400;\">&nbsp;&nbsp; &nbsp; &nbsp;&nbsp; b.存在勾选：打开弹窗进行二次确认</span></p><p><span style=\"font-family:'Nunito Sans Regular', 'Nunito Sans', sans-serif;font-weight:400;\">2.弹窗内【确认】执行：</span><span>将勾选行</span><span style=\"font-family:'Nunito Sans Regular', 'Nunito Sans', sans-serif;font-weight:400;\">“状态”</span><span>变更为'手动关闭'</span></p>",bs="12",bt="0c459efa90b8466b8a63b973af0d7ca2",bu="入库状态",bv="<p><span>1.取值描述</span></p><p><span>&nbsp;&nbsp; &nbsp; &nbsp;&nbsp; a.由[采购订单]内的【入库通知下发】初始化为'进行中'</span></p><p><span>&nbsp;&nbsp; &nbsp; &nbsp;&nbsp; b.由当前页面进行【关闭】操作后置为'手动关闭'</span></p><p><span>2.字体展示</span></p><p><span>&nbsp;&nbsp; &nbsp; &nbsp;&nbsp; a.</span><span style=\"font-family:'Nunito Sans Bold', 'Nunito Sans', sans-serif;font-weight:700;color:#4B7902;\">进行中</span><span>：绿色</span></p><p><span>&nbsp;&nbsp; &nbsp; &nbsp;&nbsp; b.</span><span style=\"font-family:'Nunito Sans Bold', 'Nunito Sans', sans-serif;font-weight:700;color:#02A7F0;\">手动关闭</span><span>：蓝色</span></p>",bw="13",bx="0bfca9c8c2914c35b3aae7231f96f1bf",by="供应商名称",bz="<p><span>1.取值描述</span></p><p><span>&nbsp;&nbsp; &nbsp; &nbsp;&nbsp; a.由[采购订单]内的【入库通知下发】初始化</span></p><p><span>&nbsp;&nbsp; &nbsp; &nbsp;&nbsp; b.由当前页面进行【关闭】操作后置为'手动关闭'</span></p>",bA="14",bB="8153d58d54064f35a847f214de22d9d3",bC="关联生产",bD="<p><span>1.取值：由[采购订单]内的【入库通知下发】初始化</span></p><p><span>&nbsp;&nbsp; &nbsp; &nbsp; &nbsp; a.该行&quot;采购订单+SKU&quot;对应的全部'生产订单号'</span></p><p><span>2.展示：若包含多个生产订单时，仅展示第一个，然后加'…'</span></p><p><span>&nbsp;&nbsp; &nbsp; &nbsp; &nbsp; a.鼠标移入：使用Tooltips展示全部去重后的'生产订单号'</span></p>",bE="15",bF="aec4dc6396fc4465b28cf1210455b7ba",bG="关联款",bH="<p><span>1.取值：由[采购订单]内的【入库通知下发】初始化</span></p><p><span>&nbsp;&nbsp; &nbsp; &nbsp; &nbsp; a.该行&quot;采购订单+SKU&quot;对应的全部'款号'</span></p><p><span>2.展示：若包含多个款号时，仅展示第一个，然后加'…'</span></p><p><span>&nbsp;&nbsp; &nbsp; &nbsp; &nbsp; a.鼠标移入：使用Tooltips展示全部去重后的'款号'</span></p>",bI="16",bJ="b253280cd84b469cb61163e7a9e4d4b5",bK="采购数量",bL="<p><span>采购订单中</span><span style=\"text-decoration:underline ;\">采购清单</span><span>内</span><span style=\"color:#0000FF;\">对应SKU</span><span>的</span><span style=\"font-family:'Nunito Sans Bold', 'Nunito Sans', sans-serif;font-weight:700;color:#D9001B;\">Σ采购数量</span></p>",bM="17",bN="32dd9a7826364867ade114db9380c8da",bO="含税单价",bP="<p><span>采购订单中</span><span style=\"text-decoration:underline ;\">采购清单</span><span>内</span><span style=\"color:#0000FF;\">对应SKU</span><span>的</span><span style=\"font-family:'Nunito Sans Bold', 'Nunito Sans', sans-serif;font-weight:700;color:#D9001B;\">加权含税单价</span></p><p><span style=\"font-family:'Nunito Sans Regular', 'Nunito Sans', sans-serif;font-weight:400;\">加权含税单价=</span><span style=\"font-family:'Nunito Sans Regular', 'Nunito Sans', sans-serif;font-weight:400;color:#4B7902;\">Σ(该SKU单行采购单价*对应行采购数量)</span><span style=\"font-family:'Nunito Sans Regular', 'Nunito Sans', sans-serif;font-weight:400;\"> / </span><span style=\"font-family:'Nunito Sans Regular', 'Nunito Sans', sans-serif;font-weight:400;color:#4B7902;\">Σ该SKU全部行采购数量</span></p>",bQ="18",bR="e48fae163b6f4d1789deab8edb3d531a",bS="附加费",bT="<p><span>采购订单中</span><span style=\"text-decoration:underline ;\">采购清单</span><span>内</span><span style=\"color:#0000FF;\">对应SKU</span><span>的</span><span style=\"font-family:'Nunito Sans Bold', 'Nunito Sans', sans-serif;font-weight:700;color:#D9001B;\">Σ附加费</span></p>",bU="19",bV="e19ac9374eba442b91f40419c599ad62",bW="订单金额",bX="<p><span>1.取值：订单金额=采购数量*含税单价+附加费</span></p><p><span>&nbsp;&nbsp; &nbsp; &nbsp; &nbsp; a.结果保留4位小数</span></p>",bY="20",bZ="f711f300d82842688b7239f7084562c9",ca="采购备注",cb="<p><span>采购订单中</span><span style=\"text-decoration:underline ;\">采购清单</span><span>内</span><span style=\"color:#0000FF;\">对应SKU</span><span>的首个'采购备注'</span></p>",cc="21",cd="508bcba7563944e6902b751d04ddb2a3",ce="要求交期",cf="<p><span>采购订单中</span><span style=\"text-decoration:underline ;\">采购清单</span><span>内</span><span style=\"color:#0000FF;\">对应SKU</span><span>的多个'交货日期'中最大的一个</span></p>",cg="22",ch="7a42e324fff947a1b18e666fb1c4242b",ci="预计到货",cj="<p><span style=\"font-family:'Nunito Sans Bold', 'Nunito Sans', sans-serif;font-weight:700;color:#02A7F0;\">日期选择器</span></p><p><span>1.初始化：由[采购订单]内的【入库通知下发】初始化</span></p><p><span>2.格式：年/月/日</span></p><p><span>3.可选项：仅可选择今日及今日之后的日期</span></p><p><span>4.每</span><span style=\"font-family:'Nunito Sans Bold', 'Nunito Sans', sans-serif;font-weight:700;color:#4B7902;\">切换</span><span>日期时，弹窗填写信息进行二次确认</span></p><p><span>&nbsp;&nbsp; &nbsp;&nbsp; a.【取消】：本次切换的日期不做变更，仍然为之前的日期</span></p><p><span>&nbsp;&nbsp; &nbsp;&nbsp; b.【确认】：变更当前物料行对应的'预计到货'日期并记录相关信息</span></p><p><span><br></span></p><p><span style=\"font-family:'Nunito Sans Bold', 'Nunito Sans', sans-serif;font-weight:700;color:#02A7F0;\">图标(变更记录)</span></p><p><span>1.弹窗展示变更记录</span></p><p><span>2.清单按“操作日期”倒叙展示</span></p>",ck="23",cl="75b93484cf8245079a06c9e2225dbdc7",cm="采购入库 数量",cn="<p><span style=\"font-family:'Arial Normal', 'Arial', sans-serif;color:#333333;\">初始化为0，其它逻辑后续补充</span></p>",co="24",cp="137fddc2282743bbad1112b6fec61d1f",cq="退货出库 数量",cr="25",cs="82c658b3614f4439abf3918abe5fba5f",ct="待入库数",cu="<p><span style=\"font-family:'Nunito Sans Regular', 'Nunito Sans', sans-serif;font-weight:400;\">1.取值：实际待入库=采购数量-采购入库数量</span></p><p><span style=\"font-family:'Nunito Sans Regular', 'Nunito Sans', sans-serif;font-weight:400;\">2.字体颜色</span></p><p><span style=\"font-family:'Nunito Sans Regular', 'Nunito Sans', sans-serif;font-weight:400;\">&nbsp;&nbsp; &nbsp; &nbsp; a.实际待入库＞0：红色</span></p><p><span style=\"font-family:'Nunito Sans Regular', 'Nunito Sans', sans-serif;font-weight:400;\">&nbsp;&nbsp; &nbsp; &nbsp; b.实际待入库 ≤ 0：黑色</span></p>",cv="26",cw="dcc1df6555b5441b9a09964c701f7691",cx="价格维护",cy="<p><span>1.维护字段：</span></p><p><span>&nbsp;&nbsp; &nbsp;&nbsp; a.未税单价和含税单价的默认值为当前的“未税单价”和“含税单价”</span></p><p><span>&nbsp;&nbsp; &nbsp;&nbsp; b.税率的默认值为当前和“含税单价”/“未税单价”</span></p><p><span>&nbsp;&nbsp; &nbsp;&nbsp; c.编辑“未税单价”时，根据“税率”实时计算“含税单价”</span></p><p><span>&nbsp;&nbsp; &nbsp;&nbsp; d.编辑“税率”时，根据“含税单价”实时计算“未税单价”</span></p><p><span>&nbsp;&nbsp; &nbsp;&nbsp; e.编辑“含税单价”时，根据“税率”实时计算“未税单价”</span></p><p><span>2.修改记录：按修改时间倒叙展示</span></p>",cz="27",cA="232a7b1306b346bd90b9300e7e3e451b",cB="确认修改",cC="<p><span>1.未税单价、税率、含税单价这3个值的结果仅保留两位小数</span></p><p><span>2.仅未税单价、税率、含税单价这3个值中产生变更时，才生成一条修改记录</span></p><p><span>3.确认修改后，刷新当前页；根据当前修改值重新计算对应行的“物料合计”和“订单金额”</span></p><p><span>&nbsp;&nbsp;&nbsp; a.&quot;物料合计&quot;=&quot;采购数量&quot; * 新&quot;含税单价&quot;</span></p><p><span>&nbsp;&nbsp;&nbsp; b.&quot;订单金额&quot;=&quot;物料合计&quot; + 新&quot;物料合计&quot;</span></p><p><span>附：仅在[采购物料清单]报表内进行的变更，不影响原采购订单(CGD</span></p>",cD="28",cE="02f0eb11ec1147be801620c665331f87",cF="供应商维护",cG="<p><span>1.维护字段：供应商</span></p><p><span>&nbsp;&nbsp; &nbsp;&nbsp; a.默认值为当前的“供应商”</span></p><p><span>&nbsp;&nbsp; &nbsp;&nbsp; b.下拉可模糊查询“供应商编码”和“供应商名称”</span></p><p><span>&nbsp;&nbsp; &nbsp;&nbsp; c.选中后只展示“供应商名称”</span></p><p><span>2.修改记录：</span></p><p><span>&nbsp;&nbsp; &nbsp;&nbsp; a.按修改时间倒叙展示</span></p><p><span>&nbsp;&nbsp; &nbsp;&nbsp; b.最后一行始终是采购订单的供应商</span></p>",cH="29",cI="ed51f74433b04d65af6c5b26bb22a967",cJ="<p><span>1.仅供应商产生变更时，才生成一条修改记录</span></p><p><span>2.确认修改后，刷新当前页；</span></p><p><span><br></span></p><p><span>附：仅在[采购物料清单]报表内进行的变更，不影响原采购订单(CGDD)，也不影响对应入库任务(RKRW)</span></p>",cK="30",cL="b948804cd21d4b6584141d03ca259cc9",cM="确认",cN="<p><span>1.“预计到货”变更成功</span></p><p><span>2.记录当前变更相关信息</span></p>",cO="31",cP="49753c787cc44e50bc29c9a3c3e93714",cQ="到货变更记录",cR="<p><span>按“操作日期”倒叙展示</span></p>",cS="style",cT="baseStyle",cU="627587b6038d43cca051c114ac41ad32",cV="pageAlignment",cW="center",cX="fill",cY="fillType",cZ="solid",da="color",db=0xFFFFFFFF,dc="image",dd="imageAlignment",de="near",df="imageRepeat",dg="auto",dh="favicon",di="sketchFactor",dj="0",dk="colorStyle",dl="appliedColor",dm="fontName",dn="Applied Font",dp="borderWidth",dq="borderVisibility",dr="borderFill",ds=0xFF797979,dt="cornerRadius",du="cornerVisibility",dv="outerShadow",dw="on",dx=false,dy="offsetX",dz=5,dA="offsetY",dB="blurRadius",dC="spread",dD="r",dE=0,dF="g",dG